from __future__ import annotations

import os
import sys
import base64
import random
from PySide6 import QtCore, QtWidgets
from behavython.gui.ui_loader import bootstrap


def main() -> int:
    """
    Application entry point.
    """
    QtCore.QCoreApplication.setAttribute(QtCore.Qt.ApplicationAttribute.AA_ShareOpenGLContexts)

    app = QtWidgets.QApplication(sys.argv)
    _window = bootstrap()

    try:
        os.system("cls")
        startup = _()
        os.system(f"echo {startup}")
        os.system("echo.")
    except Exception:
        pass

    return app.exec()


def _():
    a = b""
    messages = base64.b64decode(a).decode().split(",")
    return random.choices(messages, [1.0 + (0.3 - 1.0) * (i == len(messages) - 1) for i in range(len(messages))], k=1)[0]


if __name__ == "__main__":
    raise SystemExit(main())
